export const meta = {
  name: 'map-affine-basechange-api',
  description: 'Map Mathlib API for the affine base-change dictionary in FlatBaseChange.lean',
  phases: [{ title: 'Map', detail: 'parallel read-only API sweeps over 4 areas' }],
}

const SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['area', 'verdict', 'lemmas', 'notes'],
  properties: {
    area: { type: 'string' },
    verdict: {
      type: 'string',
      description: 'EXISTS / PARTIAL / ABSENT — does Mathlib provide what is asked, axiom-clean and usable?'
    },
    lemmas: {
      type: 'array',
      description: 'concrete declarations found, most relevant first',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['name', 'signature', 'file', 'relevance'],
        properties: {
          name: { type: 'string' },
          signature: { type: 'string' },
          file: { type: 'string' },
          relevance: { type: 'string' }
        }
      }
    },
    notes: { type: 'string', description: 'feasibility verdict + the single most-buildable axiom-clean unit you can identify in this area' }
  }
}

const REPO = '/home/archon/FormalizationProjects/Algebraic-Jacobian-Challenge'
const MATHLIB = REPO + '/.lake/packages/mathlib/Mathlib'

phase('Map')

const AREAS = [
  {
    key: 'stalk-iso-criterion',
    prompt: `Read-only Mathlib API sweep. Search ONLY inside ${MATHLIB} and the repo ${REPO}.
GOAL: find the criterion(s) that a morphism of sheaves is an isomorphism iff it is a stalkwise isomorphism, specialized as far as possible toward 'AlgebraicGeometry.Scheme.Modules' morphisms (SheafOfModules over a scheme's ringCatSheaf).
Look for: 'TopCat.Presheaf.isIso_of_stalkFunctor_map_iso', 'isIso_of_stalkFunctor', stalkwise iso criteria for TopCat.Sheaf of Ab / ModuleCat; the SheafOfModules stalk in Mathlib/Algebra/Category/ModuleCat/Sheaf/Stalk.lean; how 'Scheme.Modules.toPresheaf' reflects isos (Mathlib/AlgebraicGeometry/Modules/Sheaf.lean line ~77). Also check the repo file AlgebraicJacobian (grep) for a prior 'isIso_of_isIso_restrict' or 'restrictStalkNatIso'-based stalkwise criterion already built locally.
Report exact names, full signatures, file paths. State whether a clean 'IsIso φ ↔ ∀ x, IsIso (stalk φ x)' for Scheme.Modules can be assembled from existing pieces, and what the single missing glue lemma would be.`
  },
  {
    key: 'tilde-pushforward-pullback',
    prompt: `Read-only Mathlib API sweep. Search ONLY inside ${MATHLIB} and the repo ${REPO}.
GOAL: determine whether Mathlib relates 'AlgebraicGeometry.Scheme.Modules.pushforward (Spec.map φ)' to 'ModuleCat.restrictScalars φ', and 'Scheme.Modules.pullback (Spec.map φ)' to base change '- ⊗[R] R'' of ModuleCat, transported through the tilde construction.
Read Mathlib/AlgebraicGeometry/Modules/Tilde.lean (tilde, modulesSpecToSheaf, moduleSpecΓFunctor, tilde.functor, tilde.adjunction, SpecModulesToSheafFullyFaithful) and Mathlib/AlgebraicGeometry/Modules/Sheaf.lean (pushforward/pullback). Also search broadly for any lemma named like 'tilde_pushforward', 'pushforward_tilde', 'tilde_pullback', 'pullback_tilde', 'Spec.map' + 'tilde', 'tildeFunctorCompatibility', 'comap' on tilde.
Report exact names/signatures/files of anything that connects these, or state ABSENT with confidence. Estimate the LOC and the key sub-lemmas to BUILD such a dictionary from scratch (e.g. via 'IsLocalizedModule', 'StructureSheaf.comap', sectionwise localization).`
  },
  {
    key: 'base-change-algebra',
    prompt: `Read-only Mathlib API sweep. Search ONLY inside ${MATHLIB}.
GOAL: confirm the pure commutative-algebra isomorphisms needed for affine base change of modules, with EXACT current names/signatures (Mathlib evolves — verify, do not trust memory).
Find: 'TensorProduct.AlgebraTensorModule.cancelBaseChange' (around Mathlib/LinearAlgebra/TensorProduct/Tower.lean), and any sibling: '(R' ⊗[R] A) ⊗[A] M ≃ₗ[R'] R' ⊗[R] M'. Also find how to turn such a LinearEquiv into a 'ModuleCat' iso ('LinearEquiv.toModuleIso'), and the base-change functor on ModuleCat ('ModuleCat.restrictScalars', 'ModuleCat.extendScalars', 'ModuleCat.changeOfRings', base-change tensor). Also 'Module.Flat' and the exactness/'preserves H^0' facts for '- ⊗[A] B' when A→B flat.
Report exact names, full type signatures, file paths, and the universe/typeclass assumptions. State which are axiom-clean (assume Mathlib lemmas are).`
  },
  {
    key: 'sheafofmodules-locality',
    prompt: `Read-only Mathlib API sweep. Search ONLY inside ${MATHLIB} and repo ${REPO}.
GOAL: find any 'iso is local on an open/affine cover' criterion for SheafOfModules / Scheme.Modules morphisms, beyond the per-open 'Scheme.Modules.Hom.isIso_iff_isIso_app' (Mathlib/AlgebraicGeometry/Modules/Sheaf.lean ~line 132).
Look for: criteria reducing IsIso of a sheaf morphism to an open cover / a basis of opens / affine opens; 'isIso_iff' over a cover; quasi-coherent sheaf iso checked on affines; 'AlgebraicGeometry.Scheme.Opens.iSup' covers; 'Sheaf' iso local nature; anything in Mathlib/AlgebraicGeometry/Morphisms/ or Modules/. Also check the affine-target reduction tooling: 'IsAffineHom', 'Scheme.affineCover', 'IsPullback' of Spec squares, 'Spec' fibre product = Spec of tensor (pushout of rings): search 'Spec.map' pullback / 'PrimeSpectrum.tensorProduct' / 'AlgebraicGeometry.Spec' pushout.
Report exact names/signatures/files. State the single most-buildable axiom-clean locality lemma usable to reduce 'affineBaseChange_pushforward_iso' to affine opens.`
  },
]

const results = await parallel(AREAS.map(a => () =>
  agent(a.prompt, { label: 'map:' + a.key, phase: 'Map', schema: SCHEMA, agentType: 'Explore' })
))

return results.filter(Boolean)

